```typescript
import { setup, assign } from 'xstate';

interface Track { id: string; title: string }

interface Ctx {
  tracks: Track[];
  index: number;
}

type Ev =
  | { type: 'NEXT' }
  | { type: 'PREV' }
  | { type: 'PLAY' }
  | { type: 'PAUSE' }
  | { type: 'TOGGLE_SHUFFLE' }
  | { type: 'TOGGLE_REPEAT' };

export const playerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    hasNext: ({ context }) => context.index < context.tracks.length - 1,
    hasPrev: ({ context }) => context.index > 0
  },
  actions: {
    advance: assign({ index: ({ context }) => context.index + 1 }),
    rewind: assign({ index: ({ context }) => context.index - 1 })
  }
}).createMachine({
  id: 'player',
  type: 'parallel',
  context: { tracks: [], index: 0 },
  states: {
    transport: {
      initial: 'paused',
      states: {
        paused: { on: { PLAY: 'playing' } },
        playing: {
          on: {
            PAUSE: 'paused',
            NEXT: { guard: 'hasNext', actions: 'advance' },
            PREV: { guard: 'hasPrev', actions: 'rewind' }
          }
        }
      }
    },
    shuffle: {
      initial: 'off',
      states: {
        off: { on: { TOGGLE_SHUFFLE: 'on' } },
        on: { on: { TOGGLE_SHUFFLE: 'off' } }
      }
    },
    repeat: {
      initial: 'none',
      states: {
        none: { on: { TOGGLE_REPEAT: 'all' } },
        all: { on: { TOGGLE_REPEAT: 'one' } },
        one: { on: { TOGGLE_REPEAT: 'none' } }
      }
    }
  }
});
