import { setup, assign } from 'xstate';

interface Ctx { items: string[]; cursor: number }

type Ev =
  | { type: 'NEXT' }
  | { type: 'PREV' }
  | { type: 'SHUFFLE.ON' }
  | { type: 'SHUFFLE.OFF' };

export const playlistMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    canAdvance: ({ context }) => context.cursor + 1 < context.items.length,
    canRewind: ({ context }) => context.cursor > 0
  }
}).createMachine({
  id: 'playlist',
  type: 'parallel',
  context: { items: ['a', 'b', 'c'], cursor: 0 },
  states: {
    queue: {
      on: {
        NEXT: {
          guard: 'canAdvance',
          actions: assign({ cursor: ({ context }) => context.cursor + 1 })
        },
        PREV: {
          guard: 'canRewind',
          actions: assign({ cursor: ({ context }) => context.cursor - 1 })
        }
      }
    },
    shuffle: {
      initial: 'off',
      states: {
        off: { on: { 'SHUFFLE.ON': 'on' } },
        on: { on: { 'SHUFFLE.OFF': 'off' } }
      }
    }
  }
});
```

Use named guards in `setup.guards` that read `context` and refer to them by string name on each guarded transition. The guard rejects the event when the cursor is at a boundary.

