import { setup, assign } from 'xstate';

interface Ctx { index: number; total: number }

type Ev =
  | { type: 'NEXT' }
  | { type: 'SET_REPEAT'; mode: 'none' | 'all' | 'one' };

export const playerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    notRepeatOne: ({ context }, params: { mode: string }) => params.mode !== 'one',
    hasNext: ({ context }) => context.index + 1 < context.total
  }
}).createMachine({
  id: 'player',
  type: 'parallel',
  context: { index: 0, total: 10 },
  states: {
    repeat: {
      initial: 'none',
      states: {
        none: { on: { SET_REPEAT: [{ guard: ({ event }) => event.mode === 'all', target: 'all' }, { guard: ({ event }) => event.mode === 'one', target: 'one' }] } },
        all: { on: { SET_REPEAT: [{ guard: ({ event }) => event.mode === 'none', target: 'none' }, { guard: ({ event }) => event.mode === 'one', target: 'one' }] } },
        one: { on: { SET_REPEAT: [{ guard: ({ event }) => event.mode === 'none', target: 'none' }, { guard: ({ event }) => event.mode === 'all', target: 'all' }] } }
      }
    },
    queue: {
      on: {
        NEXT: {
          guard: 'hasNext',
          actions: assign({ index: ({ context }) => context.index + 1 })
        }
      }
    }
  }
});
