import { setup, assign, fromPromise } from 'xstate';

interface Weather { tempC: number; summary: string }
interface Ctx { city: string; data: Weather | null; fetchedAt: number; error: string | null }

type Ev = { type: 'REQUEST'; city: string } | { type: 'REFRESH' };

const fetchWeather = fromPromise<Weather, { city: string }>(async ({ input }) => {
  void input;
  return { tempC: 21, summary: 'clear' };
});

export const weatherMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { fetchWeather }
}).createMachine({
  id: 'weather',
  context: { city: '', data: null, fetchedAt: 0, error: null },
  initial: 'idle',
  states: {
    idle: {
      on: { REQUEST: { target: 'fetching', actions: assign({ city: ({ event }) => event.city }) } }
    },
    fetching: {
      invoke: {
        src: 'fetchWeather',
        input: ({ context }) => ({ city: context.city }),
        onDone: {
          target: 'stale',
          actions: assign({ data: ({ event }) => event.output, fetchedAt: () => Date.now() })
        },
        onError: {
          target: 'idle',
          actions: assign({ error: ({ event }) => String(event.error) })
        }
      }
    },
    stale: {
      after: { 60000: 'refreshing' },
      on: { REFRESH: 'refreshing' }
    },
    refreshing: {
      invoke: {
        src: 'fetchWeather',
        input: ({ context }) => ({ city: context.city }),
        onDone: {
          target: 'stale',
          actions: assign({ data: ({ event }) => event.output, fetchedAt: () => Date.now() })
        },
        onError: 'stale'
      }
    }
  }
});
```

Use a `fresh` state with an `after` delay that transitions into `revalidating`. The revalidate state invokes a promise actor and returns to `fresh` on success, letting consumers read the old `data` during the refetch.

