import { setup, assign } from 'xstate';

interface Ctx {
  target: string;
  typed: string;
  startedAt: number;
  finishedAt: number;
}

type Ev =
  | { type: 'START'; target: string }
  | { type: 'TYPE'; char: string }
  | { type: 'FINISH' };

export const typingMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
    output: {} as { wpm: number; accuracy: number }
  }
}).createMachine({
  id: 'typing',
  context: { target: '', typed: '', startedAt: 0, finishedAt: 0 },
  initial: 'ready',
  states: {
    ready: {
      on: {
        START: {
          target: 'running',
          actions: assign({
            target: ({ event }) => event.target,
            typed: () => '',
            startedAt: () => Date.now()
          })
        }
      }
    },
    running: {
      on: {
        TYPE: {
          actions: assign({ typed: ({ context, event }) => context.typed + event.char })
        },
        FINISH: {
          target: 'finished',
          actions: assign({ finishedAt: () => Date.now() })
        }
      }
    },
    finished: {
      type: 'final'
    }
  },
  output: ({ context }) => {
    const minutes = Math.max(0.001, (context.finishedAt - context.startedAt) / 60000);
    const words = context.typed.trim().split(/\s+/).filter(Boolean).length;
    const correct = Array.from(context.typed).filter((c, i) => c === context.target[i]).length;
    return {
      wpm: Math.round(words / minutes),
      accuracy: context.target.length === 0 ? 0 : correct / context.target.length
    };
  }
});
```

A machine-level `output` function runs when the machine reaches a `final` state; whatever you return is exposed via `actor.getSnapshot().output`. Declare the output shape in `types.output` so consumers get typed access. For a typing test, you compute wpm/accuracy from context once `finished` is reached.

