import { setup, assign } from 'xstate';

interface Ctx { timeMs: number; durationMs: number }

type Ev =
  | { type: 'PLAY' }
  | { type: 'PAUSE' }
  | { type: 'TICK'; deltaMs: number }
  | { type: 'SCRUB_TO'; ms: number };

export const scrubberMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    inRange: ({ context, event }) =>
      event.type === 'SCRUB_TO' && event.ms >= 0 && event.ms <= context.durationMs
  },
  actions: {
    advance: assign({
      timeMs: ({ context, event }) => {
        const next = context.timeMs + (event.type === 'TICK' ? event.deltaMs : 0);
        return Math.min(next, context.durationMs);
      }
    }),
    seek: assign({ timeMs: ({ event }) => (event.type === 'SCRUB_TO' ? event.ms : 0) })
  }
}).createMachine({
  id: 'scrubber',
  context: { timeMs: 0, durationMs: 10_000 },
  initial: 'paused',
  states: {
    paused: {
      on: {
        PLAY: 'playing',
        SCRUB_TO: { guard: 'inRange', actions: 'seek' }
      }
    },
    playing: {
      on: {
        PAUSE: 'paused',
        TICK: { actions: 'advance' },
        SCRUB_TO: { guard: 'inRange', actions: 'seek' }
      }
    }
  }
});
```

